 use std::collections::BTreeMap;
 use std::fmt;

+const MAX_VECTORS_PER_CATEGORY: usize = 1024;
+
+fn push_bounded<T>(items: &mut Vec<T>, item: T, cap: usize) {
+    if items.len() >= cap {
+        let overflow = items.len() - cap + 1;
+        items.drain(0..overflow);
+    }
+    items.push(item);
+}
